(function(){"use strict";self.onmessage=o=>{if(o.data.type==="measure"){const{delayUs:r,iterations:m,sab:a}=o.data,c=[],f=[];for(let t=0;t<m;t++){const n=performance.now();if(a){const e=new Int32Array(a);Atomics.wait(e,0,0,r/1e3)}else{const e=n+r/1e3;for(;performance.now()<e;);}const s=performance.now();c.push((s-n)*1e3)}const i=1024*1024,l=new Uint32Array(i);for(let t=0;t<5;t++){const n=performance.now();for(let e=0;e<1e4;e++){const p=e*167%i;l[p]+=e}const s=performance.now();f.push(Math.round((s-n)*1e4))}self.postMessage({type:"results",results:c,ramDna:f})}}})();
